7	/** Map every SDK entrypoint name to its source file path inside the repo. */
8	export function buildPluginSdkEntrySources(entries: readonly string[] = pluginSdkEntrypoints) {
9	  return Object.fromEntries(entries.map((entry) => [entry, `src/plugin-sdk/${entry}.ts`]));
