16	  );
17	}
18	
19	/** Build the package.json exports map for all plugin SDK subpaths. */
20	export function buildPluginSdkPackageExports() {
21	  return Object.fromEntries(
22	    pluginSdkEntrypoints.map((entry) => [
23	      entry === "index" ? "./plugin-sdk" : `./plugin-sdk/${entry}`,
24	      {
25	        types: `./dist/plugin-sdk/${entry}.d.ts`,
26	        default: `./dist/plugin-sdk/${entry}.js`,
27	      },
28	    ]),
29	  );
30	}
