386	        // Return cleanup function
387	        return {
388	          stop: () => {
389	            bus.close();
390	            activeBuses.delete(account.accountId);
391	            metricsSnapshots.delete(account.accountId);
392	            ctx.log?.info(`[${account.accountId}] Nostr provider stopped`);
393	          },
394	        };
395	      },
396	    },
397	  },
398	  pairing: {
399	    text: {
400	      idLabel: "nostrPubkey",
401	      message: "Your pairing request has been approved!",
402	      normalizeAllowEntry: (entry) => {
403	        try {
404	          return normalizePubkey(entry.trim().replace(/^nostr:/i, ""));
405	        } catch {
406	          return entry.trim();
407	        }
408	      },
409	      notify: async ({ id, message }) => {
410	        // Get the default account's bus and send approval message
411	        const bus = activeBuses.get(DEFAULT_ACCOUNT_ID);
412	        if (bus) {
413	          await bus.sendDm(id, message);
414	        }
415	      },
416	    },
417	  },
418	  security: {
419	    resolveDmPolicy: resolveNostrDmPolicy,
420	  },
421	  outbound: {
422	    deliveryMode: "direct",
423	    textChunkLimit: 4000,
424	    sendText: async ({ cfg, to, text, accountId }) => {
425	      const core = getNostrRuntime();
426	      const aid = accountId ?? DEFAULT_ACCOUNT_ID;
427	      const bus = activeBuses.get(aid);
428	      if (!bus) {
429	        throw new Error(`Nostr bus not running for account ${aid}`);
430	      }
431	      const tableMode = core.channel.text.resolveMarkdownTableMode({
432	        cfg,
433	        channel: "nostr",
434	        accountId: aid,
435	      });
436	      const message = core.channel.text.convertMarkdownTables(text ?? "", tableMode);
437	      const normalizedTo = normalizePubkey(to);
438	      await bus.sendDm(normalizedTo, message);
439	      return attachChannelToResult("nostr", {
440	        to: normalizedTo,
441	        messageId: `nostr-${Date.now()}`,
442	      });
443	    },
444	  },
445	});
446	
447	/**
448	 * Get metrics snapshot for a Nostr account.
449	 * Returns undefined if account is not running.
450	 */
451	export function getNostrMetrics(
452	  accountId: string = DEFAULT_ACCOUNT_ID,
453	): MetricsSnapshot | undefined {
454	  const bus = activeBuses.get(accountId);
455	  if (bus) {
456	    return bus.getMetrics();
457	  }
458	  return metricsSnapshots.get(accountId);
459	}
460	
461	/**
462	 * Get all active Nostr bus handles.
463	 * Useful for debugging and status reporting.
464	 */
465	export function getActiveNostrBuses(): Map<string, NostrBusHandle> {
466	  return new Map(activeBuses);
467	}
468	
469	/**
470	 * Publish a profile (kind:0) for a Nostr account.
471	 * @param accountId - Account ID (defaults to "default")
472	 * @param profile - Profile data to publish
473	 * @returns Publish results with successes and failures
474	 * @throws Error if account is not running
475	 */
476	export async function publishNostrProfile(
477	  accountId: string = DEFAULT_ACCOUNT_ID,
478	  profile: NostrProfile,
479	): Promise<ProfilePublishResult> {
480	  const bus = activeBuses.get(accountId);
481	  if (!bus) {
482	    throw new Error(`Nostr bus not running for account ${accountId}`);
483	  }
484	  return bus.publishProfile(profile);
485	}
486	
487	/**
488	 * Get profile publish state for a Nostr account.
489	 * @param accountId - Account ID (defaults to "default")
490	 * @returns Profile publish state or null if account not running
491	 */
492	export async function getNostrProfileState(accountId: string = DEFAULT_ACCOUNT_ID): Promise<{
493	  lastPublishedAt: number | null;
494	  lastPublishedEventId: string | null;
495	  lastPublishResults: Record<string, "ok" | "failed" | "timeout"> | null;
496	} | null> {
497	  const bus = activeBuses.get(accountId);
498	  if (!bus) {
499	    return null;
500	  }
501	  return bus.getProfileState();
502	}
