  listPulseBoardAccountIds,
  resolveDefaultPulseBoardAccountId,
  resolvePulseBoardAccount,
  type ResolvedPulseBoardAccount,
} from "./types.js";

const pulseBoardConfigAdapter = createTopLevelChannelConfigAdapter<
  ResolvedPulseBoardAccount
>({
  sectionKey: "pulseboard",
  resolveAccount: (cfg) => resolvePulseBoardAccount({ cfg }),
  listAccountIds: listPulseBoardAccountIds,
  defaultAccountId: resolveDefaultPulseBoardAccountId,
  deleteMode: "clear-fields",
  clearBaseFields: ["name", "defaultAccount", "apiKey", "relayUrl", "dmPolicy", "allowFrom"],
  resolveAllowFrom: (account) => account.config.allowFrom,
  formatAllowFrom: (allowFrom) =>
    allowFrom.map((entry) => String(entry).trim()).filter(Boolean),
});

const resolvePulseBoardDmPolicy = createScopedDmSecurityResolver<
  ResolvedPulseBoardAccount
>({
  channelKey: "pulseboard",
  resolvePolicy: (account) => account.config.dmPolicy,
  resolveAllowFrom: (account) => account.config.allowFrom,
  policyPathSuffix: "dmPolicy",
  defaultPolicy: "pairing",
});

export const pulseBoardSetupAdapter: ChannelSetupAdapter = {
  resolveAccountId: () => DEFAULT_ACCOUNT_ID,
  applyAccountConfig: ({ cfg, input }) => {
    const typedInput = input as { apiKey?: string; relayUrl?: string };
    return patchTopLevelChannelConfigSection({
      cfg,
      channel: "pulseboard",
      enabled: true,
      patch: {
        ...(typedInput.apiKey?.trim() ? { apiKey: typedInput.apiKey.trim() } : {}),
        ...(typedInput.relayUrl?.trim() ? { relayUrl: typedInput.relayUrl.trim() } : {}),
      },
    });
  },
};

export const pulseBoardPlugin: ChannelPlugin<ResolvedPulseBoardAccount> =
  createChatChannelPlugin({
    base: {
      id: "pulseboard",
      meta: {
        id: "pulseboard",
        label: "PulseBoard",
        selectionLabel: "PulseBoard",
        docsPath: "/channels/pulseboard",
        docsLabel: "pulseboard",
        blurb: "Realtime encrypted DMs via PulseBoard relay mesh.",
        order: 110,
      },
      capabilities: {
        chatTypes: ["direct"],
        media: false,
      },
      reload: { configPrefixes: ["channels.pulseboard"] },
      setup: pulseBoardSetupAdapter,
      config: {
        ...pulseBoardConfigAdapter,
        isConfigured: (account) => account.configured,
        describeAccount: (account) =>
          describeAccountSnapshot({
            account,
            configured: account.configured,
            extra: {
              relayUrl: account.relayUrl,
            },
          }),
      },
      messaging: {
        normalizeTarget: (target) => target.trim().toLowerCase(),
        targetResolver: {
          looksLikeId: (input) => /^[a-zA-Z0-9_-]+$/.test(input.trim()),
          hint: "<pulseboard-user-id>",
        },
      },
      status: createComputedAccountStatusAdapter<ResolvedPulseBoardAccount>({
        defaultRuntime: createDefaultChannelRuntimeState(DEFAULT_ACCOUNT_ID),
        buildChannelSummary: ({ snapshot }) =>
          buildPassiveChannelStatusSummary(snapshot, {
            relayUrl: snapshot.relayUrl ?? null,
          }),
        resolveAccountSnapshot: ({ account }) => ({
          accountId: account.accountId,
          name: account.name,
          enabled: account.enabled,
          configured: account.configured,
          extra: {
            relayUrl: account.relayUrl,
          },
        }),
      }),
      gateway: {
        startAccount: async (ctx) => {
          const account = ctx.account;
          if (!account.configured) {
            throw new Error(
              `PulseBoard is not configured for account "${account.accountId}" (need apiKey in channels.pulseboard).`,
            );
          }
          ctx.log?.info(
            `[${account.accountId}] starting PulseBoard provider (relay: ${account.relayUrl})`,
          );
          // Stub: no actual connection logic
        },
      },
    },
    pairing: {
      text: {
        idLabel: "pulseBoardUserId",
        message: "Your PulseBoard pairing request has been approved!",
        notify: async ({ id, message }) => {
          // Stub: would send approval notification to the user
          void id;
          void message;
        },
      },
    },
    security: {
      resolveDmPolicy: resolvePulseBoardDmPolicy,
    },
    outbound: {
      deliveryMode: "direct",
      textChunkLimit: 4000,
      sendText: async ({ to, text }) => {
        // Stub: would send text via PulseBoard relay
        return attachChannelToResult("pulseboard", {
          to,
          messageId: `pulseboard-${Date.now()}`,
        });
      },
    },
  });
```

**Rationale:**

- **Meta inlining**: PulseBoard is not registered in the core `chat-meta` registry, so we inline the meta object directly in the base config (following Nostr's pattern at line 148-158 of its `channel.ts`).
- **Config adapter**: Uses `createTopLevelChannelConfigAdapter` (same as Nostr) rather than `createScopedChannelConfigAdapter` (IRC), since PulseBoard has a single-account top-level config structure.
- **Setup adapter**: The `applyAccountConfig` function is the only required property of `ChannelSetupAdapter` (line 79 of `types.adapters.ts`). It uses `patchTopLevelChannelConfigSection` from `openclaw/plugin-sdk/setup`, matching how Nostr patches its channel config section.
- **Status adapter**: Uses `createComputedAccountStatusAdapter` with `createDefaultChannelRuntimeState` and `buildPassiveChannelStatusSummary`, all from their respective SDK modules. This matches the Nostr pattern.
- **Outbound**: Uses `attachChannelToResult` from `openclaw/plugin-sdk/channel-send-result` (same pattern as Nostr line 439). The `createChatChannelPlugin` function accepts a "flat" outbound (without `base`+`attachedResults` nesting) as seen in the Nostr plugin's outbound adapter.
- **Security**: Uses `createScopedDmSecurityResolver` following Nostr's pattern.
- **Pairing**: Uses the `text` shorthand form that `createChatChannelPlugin` processes via `createInlineTextPairingAdapter` (line 85-102 of core.ts).
- **Gateway**: The `startAccount` function is a stub. In a real implementation it would open a WebSocket to the PulseBoard relay and dispatch inbound messages.

---

### File 6: `extensions/pulseboard/index.ts`

This follows the IRC pattern exactly: import `defineChannelPluginEntry`, the plugin, and the `setRuntime` function.

**Contents:**
```typescript
import type { ChannelPlugin } from "openclaw/plugin-sdk/core";
import { defineChannelPluginEntry } from "openclaw/plugin-sdk/core";
import { pulseBoardPlugin } from "./src/channel.js";
import { setPulseBoardRuntime } from "./src/runtime.js";

export { pulseBoardPlugin } from "./src/channel.js";
export { setPulseBoardRuntime } from "./src/runtime.js";

export default defineChannelPluginEntry({
  id: "pulseboard",
  name: "PulseBoard",
  description: "PulseBoard channel plugin",
  plugin: pulseBoardPlugin as ChannelPlugin,
  setRuntime: setPulseBoardRuntime,
});
```

**Rationale:** This mirrors IRC's `index.ts` exactly. The `as ChannelPlugin` cast is needed because the plugin has a generic type parameter `ChannelPlugin<ResolvedPulseBoardAccount>` while `defineChannelPluginEntry` expects the base `ChannelPlugin`. The `export default` is what the plugin loader reads. The named re-exports make the plugin and runtime setter available for programmatic use.

---

### File 7: `extensions/pulseboard/setup-entry.ts`

This follows the exact pattern of both IRC and Nostr.

**Contents:**
```typescript
import { defineSetupPluginEntry } from "openclaw/plugin-sdk/core";
import { pulseBoardPlugin } from "./src/channel.js";

export default defineSetupPluginEntry(pulseBoardPlugin);
```

**Rationale:** The setup entry is loaded separately from the main entry during the setup wizard flow. It only needs to expose the plugin object (which contains the `setup` adapter). Both IRC and Nostr use this exact pattern.

---

### File Creation Order and Dependencies

The files should be created in this order based on import dependencies:

1. `extensions/pulseboard/package.json` -- no dependencies, defines the package
2. `extensions/pulseboard/openclaw.plugin.json` -- no dependencies, plugin manifest
3. `extensions/pulseboard/src/types.ts` -- depends only on SDK imports
4. `extensions/pulseboard/src/runtime.ts` -- depends only on SDK imports
5. `extensions/pulseboard/src/channel.ts` -- depends on `./types.js` and `./runtime.js`
6. `extensions/pulseboard/index.ts` -- depends on `./src/channel.js` and `./src/runtime.js`
7. `extensions/pulseboard/setup-entry.ts` -- depends on `./src/channel.js`

The `extensions/pulseboard/src/` directory must be created before files 3-5.

### Potential Challenges

1. **SDK subpath resolution**: The `openclaw/plugin-sdk/*` imports resolve via the monorepo `package.json` exports map. Since PulseBoard is under `extensions/` and has `openclaw` as a `devDependency` with `workspace:*`, these imports will resolve correctly in the monorepo context.

2. **Missing `getChatChannelMeta` registration**: The `getChatChannelMeta` function in core uses a registry of known channels. Since PulseBoard is not registered there, we inline the meta object directly (as Nostr does). If `getChatChannelMeta("pulseboard")` were called it would fail -- this is why inlining is the correct approach.

3. **Type narrowing for config access**: The `cfg.channels` property is typed as `ChannelsConfig` which does not have a `pulseboard` key. Both IRC and Nostr cast through `Record<string, unknown>` to access their channel-specific config. PulseBoard follows the same pattern.

4. **Outbound adapter shape**: The `createChatChannelPlugin` function accepts two outbound shapes: a "flat" `ChannelOutboundAdapter` or a `{ base, attachedResults }` object. Nostr uses the flat form directly with `sendText`, while IRC uses the `{ base, attachedResults }` form. For PulseBoard's simpler stub, the flat form (matching Nostr) is appropriate.

### Critical Files for Implementation

- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386619349-c0p56y/extensions/nostr/src/channel.ts` -- Primary reference for the `createChatChannelPlugin` call structure, DM-focused channel pattern, and inline meta
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386619349-c0p56y/extensions/nostr/src/types.ts` -- Primary reference for account resolution pattern with SDK helpers
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386619349-c0p56y/extensions/irc/index.ts` -- Primary reference for `defineChannelPluginEntry` usage
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386619349-c0p56y/src/plugin-sdk/core.ts` -- SDK source of truth for `createChatChannelPlugin`, `defineChannelPluginEntry`, `defineSetupPluginEntry`, and all exported types
- `/private/var/folders/vq/9q38rw0x2455zr_whqcrjbhr0000gn/T/planmode-bench-wt-run-1775386619349-c0p56y/src/channels/plugins/types.adapters.ts` -- Type definitions for `ChannelSetupAdapter`, `ChannelConfigAdapter`, confirming required vs optional fields

