import type { ChannelPlugin, OpenClawConfig } from "openclaw/plugin-sdk/core";
import { createChatChannelPlugin } from "openclaw/plugin-sdk/core";
import { getPulseBoardRuntime } from "./runtime.js";

export const pulseBoardPlugin: ChannelPlugin = createChatChannelPlugin({
  base: {
    id: "pulseboard",
    meta: {
      id: "pulseboard",
      label: "PulseBoard",
      selectionLabel: "PulseBoard (Bulletin)",
      docsPath: "/channels/pulseboard",
      docsLabel: "pulseboard",
      blurb: "Real-time bulletin board messaging with boards and direct messages.",
      order: 200,
    },
    capabilities: {
      chatTypes: ["direct", "group"],
      media: false,
    },
    reload: { configPrefixes: ["channels.pulseboard"] },
    config: {
      resolveAccount: ({ cfg, accountId }) => ({
        accountId: accountId ?? "default",
        enabled: true,
        configured: false,
      }),
      listAccountIds: () => ["default"],
      defaultAccountId: () => "default",
    },
    setup: {
      applyAccountConfig: ({ cfg }: { cfg: OpenClawConfig; accountId: string; input: Record<string, unknown> }) => {
        return cfg;
      },
    },
    gateway: {
      startAccount: async (ctx) => {
        ctx.log?.info(`[${ctx.account.accountId}] starting PulseBoard connection`);
        return {
          stop: () => {
            ctx.log?.info(`[${ctx.account.accountId}] PulseBoard connection stopped`);
          },
        };
      },
    },
    messaging: {
      normalizeTarget: (target: string) => target.trim(),
    },
  },
  outbound: {
    deliveryMode: "direct",
    textChunkLimit: 4000,
    sendText: async ({ to }) => {
      return {
        channel: "pulseboard",
        to,
        messageId: `pb-${Date.now()}`,
      };
    },
  },
});

